INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f0d2367ace5a8cb5a3',NULL,'fierce','/fiәs/','a. 凶猛的, 猛烈的, 热烈的, 暴躁的；英英释义：s. marked by extreme intensity of emotions or convictions; inclined to react violently; fervid；词形变化：t:fiercest/r:fiercer','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4d26f6d43e08184126',NULL,'fight','/fait/','n. 打架, 争吵, 斗志\nv. 对抗, 打架；英英释义：n. the act of fighting; any contest or struggle\nn. an intense verbal dispute\nn. a boxing or wrestling match\nv. fight against or resist strongly；词形变化：i:fighting/p:fought/d:fought/s:fights/3:fights','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d37dfed76ffcac1fad',NULL,'figure','/''figә/','n. 数字, 价格, 图形, 形状\nvt. 描绘, 表示, 演算, 认为\nvi. 计算, 出现, 估计；英英释义：n. a diagram or picture illustrating textual material\nn. a model of a bodily form (especially of a person)\nn. a combination of points and lines and planes that form a visible palpable shape\nn. an amount of money expressed numerically；词形变化：s:figures/p:figured/d:figured/3:figures/i:figuring','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_fe78e6b1ac905b9b5a',NULL,'file','/fail/','n. 档案, 公文箱, 文件夹, 文件, 卷宗, 锉刀\nvi. 列队行进, 用锉刀做\nvt. 归档, 申请, 锉, 琢磨\n[计] 文件；英英释义：n. a set of related records (either written or electronic) kept together\nn. a line of persons or things ranged one behind the other\nn. office furniture consisting of a container for keeping papers in order\nn. a steel hand tool with small sharp teeth on some or all of its surfaces; used for smoothing wood or metal；词形变化：s:files/d:filed/p:filed/i:filing/3:files','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_dde45e7a54af0d1b5f',NULL,'filter','/''filtә/','n. 滤波器, 过滤器, 滤光器, 过滤嘴, 去尘器\nvt. 过滤, 渗透, 走漏\nvi. 滤过, 渗入\n[计] 过滤器, 筛选；英英释义：n. device that removes something from whatever passes through it\nn. an electrical device that alters the frequency spectrum of signals passing through it\nv. remove by passing through a filter；词形变化：s:filters/d:filtered/i:filtering/3:filters/p:filtered','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
