INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a4a7e10189c506b476',NULL,'finite','/''fainait/','a. 有限的, 有穷的, 限定的\nn. 有限物；英英释义：a. bounded or limited in magnitude or spatial or temporal extent\na. of verbs; relating to forms of the verb that are limited in time by a tense and (usually) show agreement with number and person；词形变化：s:finites','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
