INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_591a11b547f25d0785',NULL,'fitting','/''fitiŋ/','a. 适宜的\nn. 试穿, 试衣, 装配, 装置；英英释义：n. a small and often standardized accessory to a larger system\nn. putting clothes on to see whether they fit\ns. in harmony with the spirit of particular persons or occasion\ns. being precisely fitting and right；词形变化：0:fit/1:i/s:fittings/i:fitting','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2f5bb3686c45d3d89b',NULL,'fix','/fiks/','vt. 使固定, 修理, 准备, 安装, 凝视, 牢记, 确定, 整理\nvi. 固定, 注视, 确定\nn. 困境, 方位, 维修, 贿赂；英英释义：n. informal terms for a difficult situation\nn. something craved, especially an intravenous injection of a narcotic drug\nn. an exemption granted after influence (e.g., money) is brought to bear\nv. set or place definitely；词形变化：d:fixed/i:fixing/p:fixed/3:fixes/s:fixes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
