INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2e1490da68d6919642',NULL,'flame','/fleim/','n. 火焰, 火舌, 热情, 光辉\nvt. 焚烧, 用火焰给...灭菌, 用火焰传送(信号), 点燃, 激动\nvi. 燃烧, 爆发, 闪耀\n[计] 无聊邮件, 无益邮件；英英释义：v. be in flames or aflame\nv. criticize harshly, usually via an electronic medium；词形变化：s:flames/p:flamed/i:flaming/d:flamed/3:flames','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_7614e498f12b126928',NULL,'flap','/flæp/','n. 飘, 摆动, 拍打, 拍打声, 片状垂悬物\nv. 拍打, 鼓翼而飞, 飘动；英英释义：n. any broad thin and limber covering attached at one edge; hangs loose or projects freely\nn. the motion made by flapping up and down\nn. a movable piece of tissue partly connected to the body\nn. a movable airfoil that is part of an aircraft wing; used to increase lift or drag；词形变化：i:flapping/p:flapped/s:flaps/3:flaps/d:flapped','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_18d91c8ea150927ecb',NULL,'flare','/''flєә/','n. 闪光, 闪耀\nvi. 闪光, 闪耀\nvt. 用发光信号发出, 使闪耀, 使张开；英英释义：n. a shape that spreads outward\nn. a sudden burst of flame\nn. a burst of light used to communicate or illuminate\nn. reddening of the skin spreading outward from a focus of infection or irritation；词形变化：p:flared/s:flares/i:flaring/d:flared/3:flares','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_04482a106d388d0f73',NULL,'flash','/flæʃ/','n. 闪光, 闪现, 一瞬间\nvi. 闪光, 闪现, 反射\nvt. 使闪光, 反射；英英释义：n. a sudden intense burst of radiant energy\nn. a momentary brightness\nn. a short vivid experience\nn. a sudden brilliant understanding；词形变化：p:flashed/i:flashing/s:flashes/d:flashed/3:flashes/r:flasher','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1f33986492344a8127',NULL,'flat','/flæt/','a. 平坦的, 单调的, 无力的, 浅的, 萧条的, 干脆的, 无聊的\nadv. 平直地, 断然地\nn. 扁平物, 平面, 平地, 平原, 平板车\nv. (使)变平；英英释义：n. a level tract of land\nn. a shallow box in which seedlings are started\nn. a musical notation indicating one half step lower than the note named\nn. a deflated pneumatic tire；词形变化：s:flats/r:flatter','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
