INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_30977c4cf1be96a90e',NULL,'flour','/''flauә/','n. 面粉, 粉沫, 碎粉\n[医] 面粉, 麦粉；英英释义：n. fine powdery foodstuff obtained by grinding and sifting the meal of a cereal grain\nv. cover with flour\nv. convert grain into flour；词形变化：s:flours/p:floured/i:flouring/3:flours/d:floured','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
