INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('7fd85f95-a2ea-4bc6-9a37-8e8c7df8d940',NULL,'fluctuate','/''flʌktʃueit/','vi. 变动, 起伏, 动摇\nvt. 使波动, 使动摇；英英释义：v. cause to fluctuate or move in a wavelike pattern\nv. move or sway in a rising and falling or wavelike pattern\nv. be unstable；词形变化：p:fluctuated/3:fluctuates/d:fluctuated/i:fluctuating','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('8a97e504-1102-46c8-9178-861f7f3faba4',NULL,'fluctuation','/.flʌktʃu''eiʃәn/','n. 变动, 波动, 动摇\n[化] 涨落; 起伏; 波动; 脉动；英英释义：n. a wave motion\nn. the quality of being unsteady and subject to changes；词形变化：s:fluctuations','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
