INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4f705f8e704ac0f39b',NULL,'freeze','/fri:z/','vi. 冻结, 冷冻, 僵硬, 楞住\nvt. 使结冰, 使冻住, 使呆住\nn. 结冰, 凝固\n[计] 冻结；英英释义：n. the withdrawal of heat to change something from a liquid to a solid\nn. weather cold enough to cause freezing\nn. an interruption or temporary suspension of progress or movement\nn. fixing (of prices or wages etc) at a particular level；词形变化：d:frozen/p:froze/3:freezes/i:freezing/s:freezes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
