INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a8a97be19e5881c937',NULL,'frost','/frɒst/','n. 霜, 冰冻, 冷漠\nvt. 覆着霜, 冻结, 结霜\nvi. 受冻, 起霜；英英释义：n. ice crystals forming a white deposit (especially on objects outside)\nn. the formation of frost or ice on a surface\nn. United States poet famous for his lyrical poems on country life in New England (1874-1963)\nv. decorate with frosting；词形变化：s:frosts/i:frosting/d:frosted/p:frosted/3:frosts','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
