INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a0d68dbcc0c10fb67c',NULL,'ideal','/ai''diәl/','n. 理想, 典范, 观念, 思想, 最后目标\na. 理想的, 完美的, 空想的, 观念的, 唯心论的；英英释义：n. the idea of something that is perfect; something that one hopes to attain\nn. model of excellence or perfection of a kind; one having no equal\ns. conforming to an ultimate standard of perfection or excellence; embodying an ideal\ns. constituting or existing only in the form of an idea or mental image or conception；词形变化：s:ideals','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f66914e001ea4fb245',NULL,'identical','/ai''dentikәl/','a. 同一的, 恒等的, 完全相同的\n[医] 同一的, 同等的；英英释义：s. exactly alike; incapable of being perceived as different\ns. being the exact same one; not any other:\na. (of twins) derived from a single egg or ovum\ns. having properties with uniform values along all axes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_56049f50651e801f6b',NULL,'identification','/ai.dentifi''keiʃәn/','n. 识别, 身份证明, 认同\n[化] 鉴定; 鉴别; 鉴别法; 认证；英英释义：n. evidence of identity; something that identifies a person or thing\nn. the condition of having the identity (of a person or object) established\nn. the attribution to yourself (consciously or unconsciously) of the characteristics of another person (or group of persons)；词形变化：s:identifications','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0e442d62201a60b737',NULL,'identify','/ai''dentifai/','vt. 识别, 认为...等同于, 确定, 使参与\nvi. 一致, 认同；英英释义：v. recognize as being; establish the identity of someone or something\nv. consider (oneself) as similar to somebody else\nv. conceive of as united or associated\nv. identify as in botany or biology, for example；词形变化：d:identified/i:identifying/3:identifies/p:identified','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_99ce55ad31144d66a0',NULL,'identity','/ai''dentiti/','n. 身份, 相同, 一致, 特性, 恒等式\n[计] (打)标记, 标识；英英释义：n. the distinct personality of an individual regarded as a persisting entity\nn. the individual characteristics by which a thing or person is recognized or known\nn. an operator that leaves unchanged the element on which it operates\nn. exact sameness；词形变化：s:identities','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
