INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_7477e5285441d725e2',NULL,'infect','/in''fekt/','vt. 传染, 感染\n[医] 传染, 感染；英英释义：v. communicate a disease to\nv. contaminate with a disease or microorganism\nv. corrupt with ideas or an ideology\nv. affect in a contagious way；词形变化：d:infected/p:infected/3:infects/i:infecting/s:infects','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6d0eba94cc4bbfbd5f',NULL,'infection','/in''fekʃәn/','n. 传染, 影响, 传染病\n[医] 传染, 感染；英英释义：n. the pathological state resulting from the invasion of the body by pathogenic microorganisms\nn. (phonetics) the alteration of a speech sound under the influence of a neighboring sound\nn. (medicine) the invasion of the body by pathogenic microorganisms and their multiplication which can lead to tissue damage and disease\nn. an incident in which an infectious disease is transmitted；词形变化：s:infections','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
