INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('f93d8e54-94ea-40b5-bf8d-d1d7cedca1e6',NULL,'inference','/''infәrәns/','n. 推论\n[法] 推论, 推理, 推断；英英释义：n. the reasoning involved in drawing a conclusion or making a logical judgment on the basis of circumstantial evidence and prior conclusions rather than on the basis of direct observation；词形变化：s:inferences/i:inferencing','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
