INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_cbca38b6a36058f753',NULL,'infinite','/''infinit/','n. 无限, 神\na. 无穷的, 无限的, 极大的；英英释义：a. having no limits or boundaries in time or space or extent or magnitude\na. of verbs; having neither person nor number nor mood (as a participle or gerund or infinitive)\ns. total and all-embracing','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_96f4b2000538dcd90d',NULL,'inflation','/in''fleiʃәn/','n. 胀大, 夸张, 通货膨胀\n[化] 充气吹胀; 膨胀；英英释义：n. a general and progressive increase in prices\nn. (cosmology) a brief exponential expansion of the universe (faster than the speed of light) postulated to have occurred shortly after the big bang\nn. the act of filling something with air；词形变化：s:inflations','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0f1e6973592d725af7',NULL,'influence','/''influәns/','n. 影响力, 权力, 势力\nvt. 影响, 改变；英英释义：n. a power to affect persons or events especially power based on prestige etc\nn. causing something without any direct or apparent effort\nn. a cognitive factor that tends to have an effect on what you do\nn. the effect of one thing (or person) on another；词形变化：d:influenced/s:influences/i:influencing/3:influences/p:influenced','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
