INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ebcf6f64feeccce943',NULL,'interest','/''intrist/','n. 兴趣, 嗜好, 利息, 利益, 爱好, 趣味, 势力\nvt. 使感兴趣, 与...有关系；英英释义：n. a sense of concern with and curiosity about someone or something\nn. the power of attracting or holding one''s attention (because it is unusual or exciting etc.)\nn. a fixed charge for borrowing money; usually a percentage of the amount borrowed\nn. (law) a right or legal share of something; a financial involvement with something；词形变化：s:interests/3:interests/p:interested/d:interested/i:interesting','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_70cc5ae8a9e206f408',NULL,'interface','/''intәfeis/','n. 分界面, 接触面, 界面\n[计] 接口, 界面；英英释义：n. (chemistry) a surface forming a common boundary between two things (two objects or liquids or chemical phases)\nn. (computer science) a program that controls a display for the user (usually on a computer monitor) and that allows the user to interact with the system\nn. the overlap where two theories or phenomena affect each other or have links with each other\nn. (computer science) computer circuit consisting of the hardware and associated circuitry that links one device with another (especially a computer and a hard disk drive or other peripherals)；词形变化：s:interfaces/d:interfaced/p:interfaced/3:interfaces','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
