INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_899af7b74f4b9cd1d9',NULL,'intersect','/.intә''sekt/','vt. 贯穿, 横穿\nvi. 交错, 相交；英英释义：v. meet at a point；词形变化：3:intersects/p:intersected/i:intersecting/d:intersected','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4330d808cefe2b9f99',NULL,'intersection','/.intә''sekʃәn/','n. 交集, 十字路口, 交叉点\n[计] 逻辑乘; 与；英英释义：n. a point where lines intersect\nn. a junction where one street or road crosses another\nn. a point or set of points common to two or more geometric configurations；词形变化：s:intersections/i:intersectioning','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8fd72f9b5c928921b9',NULL,'interval','/''intәvәl/','n. 间隔, 距离, 间歇, 间隙\n[计] 时间间隔；英英释义：n. a set containing all points (or all real numbers) between two given endpoints\nn. the distance between things\nn. the difference in pitch between two notes；词形变化：s:intervals','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
