INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0c509f944de444bd1a',NULL,'interview','/''intәvju:/','n. 面谈, 访问, 接见, 面试\nvt. 接见, 对...进行面谈(试)；英英释义：n. the questioning of a person (or a conversation in which information is elicited); often conducted by journalists\nv. conduct an interview in television, newspaper, and radio reporting\nv. discuss formally with (somebody) for the purpose of an evaluation\nv. go for an interview in the hope of being hired；词形变化：s:interviews/d:interviewed/p:interviewed/i:interviewing/3:interviews','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_3e641475a8458a213b',NULL,'intimate','/''intimәt/','a. 亲密的, 私人的, 秘密的\nvt. 暗示, 通知, 告诉\nn. 至交；英英释义：v. give to understand\ns. marked by close acquaintance, association, or familiarity\ns. involved in a sexual relationship\ns. thoroughly acquainted through study or experience；词形变化：d:intimated/p:intimated/3:intimates/i:intimating','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
