INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1fb9ceb101d0b8b2ff',NULL,'intrigue','/in''tri:g/','n. 阴谋, 复杂的事\nvi. 密谋, 私通\nvt. 激起...的兴趣, 用诡计取得；英英释义：n. a crafty and involved plot to achieve your (usually sinister) ends\nn. a clandestine love affair\nv. cause to be interested or curious；词形变化：s:intrigues/d:intrigued/p:intrigued/i:intriguing/3:intrigues','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d1893e9c6f52393720',NULL,'intriguing','/in''tri:giŋ/','a. 吸引人的, 有趣的；英英释义：s. capable of arousing interest or curiosity；词形变化：1:i/0:intrigue','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
