INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d782b369367ab66825',NULL,'jazz','/dʒæz/','n. 爵士乐, 喧闹\na. 爵士乐的, 喧吵的\nvi. 演奏爵士乐, 跳爵士舞, 游荡\nvt. 奏爵士乐, 使活泼；英英释义：n. a genre of popular music that originated in New Orleans around 1900 and developed through increasingly complex styles\nn. a style of dance music popular in the 1920s; similar to New Orleans jazz but played by large bands\nv. play something in the style of jazz；词形变化：i:jazzing/p:jazzed/3:jazzes/d:jazzed','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
