INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_25ffc01d384b454188',NULL,'joke','/dʒәuk/','n. 笑话, 玩笑, 笑柄\nv. 开玩笑, 取笑, 作弄；英英释义：n. a humorous anecdote or remark intended to provoke laughter\nn. a triviality not to be taken seriously\nv. tell a joke; speak humorously\nv. act in a funny or teasing way；词形变化：s:jokes/i:joking/p:joked/3:jokes/d:joked','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
