INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f7edb45912f2e1bff1',NULL,'judgement','/''dʒʌdʒmәnt/','n. 审判, 判决, 判断\n[经] 判定, 审定, 鉴定；英英释义：n the legal document stating the reasons for a judicial decision\nn an opinion formed by judging something\nn the cognitive process of reaching a decision or drawing conclusions\nn the mental ability to understand and discriminate between relations\nn the capacity to assess situations or circumstances shrewdly and to draw sound conclusions\nn (law) the determination by a court of competent jurisdiction on matters submitted to it\nn the act of judging or assessing a person or situation or event；词形变化：s:judgements','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('ef157b31-8399-459d-8696-a009bfde92ec',NULL,'judicial','/dʒu:''diʃәl/','a. 法庭的, 公正的, 审判上的, 司法的\n[法] 司法的, 审判上的, 法官的；英英释义：s. decreed by or proceeding from a court of justice\na. belonging or appropriate to the office of a judge\na. relating to the administration of justice or the function of a judge','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
