INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ee13e1c8c126a8b6da',NULL,'junction','/''dʒʌŋkʃәn/','n. 连接, 会合处, 交叉点\n[医] 接[合]处, 接点.[接]界；英英释义：n. the place where two or more things come together\nn. the state of being joined together\nn. something that joins or connects\nn. an act of joining or adjoining things；词形变化：s:junctions','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
