INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8751ae1b9608204e84',NULL,'leisure','/''li:ʒә/','n. 空闲, 闲暇, 悠闲\na. 空闲的, 有闲的；英英释义：n. time available for ease and relaxation\nn. freedom to choose a pastime or enjoyable activity；词形变化：p:leisured','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_3fd8756f53a60d6502',NULL,'lemon','/''lemәn/','n. 柠檬, 柠檬树, 柠檬色\n[医] 柠檬；英英释义：n. yellow oval fruit with juicy acidic flesh\nn. a small evergreen tree that originated in Asia but is widely cultivated for its fruit\nn. a distinctive tart flavor characteristic of lemons\nn. an artifact (especially an automobile) that is defective or unsatisfactory；词形变化：s:lemons','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_74823986c29a2cf5dc',NULL,'length','/leŋθ/','n. 长度, 长, 期间, 一段\n[计] 记录长度; 块长; 字长；英英释义：n. the linear extent in space from one end to the other; the longest dimension of something that is fixed in place\nn. the property of being the extent of something from beginning to end\nn. a section of something that is long and narrow；词形变化：s:lengths','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_414b1e3bdb86119ad6',NULL,'lens','/lenz/','n. 透镜, 镜头, 镜片, 晶状体\nvt. 给...摄影；英英释义：n. a transparent optical device used to converge or diverge transmitted light and to form images\nn. genus of small erect or climbing herbs with pinnate leaves and small inconspicuous white flowers and small flattened pods: lentils\nn. (metaphor) a channel through which something can be seen or understood\nn. biconvex transparent body situated behind the iris in the eye; its role (along with the cornea) is to focuses light on the retina','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_345e3fd11808a7872f',NULL,'less','/les/','n. 较少, 较小\na. 少的, 小的\nadv. 较少, 较小, 较差\n[计] 最低成本估算与调度法；英英释义：a. (comparative of `little'' usually used with mass nouns) a quantifier meaning not as great in amount or degree\ns. (usually preceded by `no'') lower in quality\ns. (nonstandard in some uses but often idiomatic with measure phrases) fewer\nr. used to form the comparative of some adjectives and adverbs','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_532e75d0960295c65c',NULL,'lest','/lest/','conj. 以免, 唯恐, 免得；英英释义：s being ten more than forty','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5fba1f6ab65f69ff2d',NULL,'level','/''levl/','n. 水平, 水准, 平地\na. 同高的, 平坦的, 齐平的, 水平的\nvt. 弄平, 夷平, 使同等, 瞄准, 对准\nvi. 变平, 拉平\n[计] 级别；英英释义：n. height above ground\nn. indicator that establishes the horizontal when a bubble is centered in a tube of liquid\nn. an abstract place usually conceived as having depth\nv. aim at；词形变化：s:levels/d:levelled/p:levelled/i:levelling/3:levels','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_846d043e857abe2588',NULL,'lever','/''levә/','n. 杠杆, 似杠杆之工具\nvt. 撬开\nvi. 使用杠杆；英英释义：n. a rigid bar pivoted about a fulcrum\nn. a simple machine that gives a mechanical advantage when given a fulcrum\nn. a flat metal tumbler in a lever lock；词形变化：s:levers/p:levered/i:levering/d:levered/3:levers','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('166678e3-ebf6-4db8-8c11-dad1b09277a5',NULL,'leverage','/''levәridʒ/','n. 杠杆作用, 杠杆装置, 杠杆效率\n[医] 杠杆率；英英释义：n. the mechanical advantage gained by being in a position to use a lever\nn. strategic advantage; power to act effectively\nn. investing with borrowed money as a way to amplify potential gains (at the risk of greater losses)\nv. supplement with leverage；词形变化：i:leveraging/d:leveraged/s:leverages/p:leveraged/3:leverages','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f3c778b7a3dbade110',NULL,'levy','/''levi/','n. 税款, 所征的人数, 征收\nvi. 征税, 课税\nvt. 征收, 强求, 召集；英英释义：n. a charge imposed and collected\nn. the act of drafting into military service\nv. impose and collect；词形变化：d:levied/s:levies/i:levying/p:levied/3:levies','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e414ef5062487b37ff',NULL,'liability','/laiә''biliti/','n. 责任, 债务, 倾向\n[经] 责任, 义务, 负债；英英释义：n. the state of being legally obliged and responsible\nn. the quality of being something that holds you back；词形变化：s:liabilities','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_9cb4c71bc3ffde8a59',NULL,'liable','/''laiәbl/','a. 有义务的, 应负责的, 有...倾向的\n[法] 有责任的, 可受处理的, 应受罚的；英英释义：s. subject to legal action\ns. (often followed by `to'') likely to be affected with\ns. held legally responsible','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_825f51fc6b11c0d938',NULL,'liberal','/''libәrәl/','n. 自由主义者\na. 慷慨的, 不拘泥的, 宽大的, 自由主义的；英英释义：n. a person who favors a political philosophy of progress and reform and the protection of civil liberties\nn. a person who favors an economic theory of laissez-faire and self-regulating markets\ns. having political or social views favoring reform and progress\na. tolerant of change; not bound by authoritarianism, orthodoxy, or tradition；词形变化：s:liberals','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_9c6836b3486672d09b',NULL,'liberate','/''libәreit/','vt. 解放, 释放, 使自由\n[机] 释出, 放出；英英释义：v. grant freedom to；词形变化：d:liberated/p:liberated/3:liberates/i:liberating','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_965b4134f887925c3d',NULL,'liberty','/''libәli/','n. 自由, 特权, 许可, 冒失\n[法] 自由, 自由权, 自由区域；英英释义：n. freedom of choice\nn. personal freedom from servitude or confinement or oppression；词形变化：s:liberties','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8ed1f425ba3a6ed5a0',NULL,'librarian','/lai''brєәriәn/','n. 图书馆员, 图书管理员\n[计] 程序库管理程序; 程序库生成程序；英英释义：n. a professional person trained in library science and engaged in library services；词形变化：s:librarians','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d2128e8f7af3634c3e',NULL,'license','/''laisns/','n. 执照, 许可证, 特许\nvt. 许可, 特许；英英释义：n. a legal document giving official permission to do something\nn. freedom to deviate deliberately from normally applicable rules or practices (especially in behavior or speech)\nn. excessive freedom; lack of due restraint\nn. the act of giving a formal (usually written) authorization；词形变化：d:licensed/i:licensing/s:licenses/3:licenses/p:licensed','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ad20e477b90217957e',NULL,'lick','/lik/','n. 舔, 少许, 打\nvt. 舔, 卷过, 鞭打\nvi. 轻轻拍打；英英释义：n. touching with the tongue\nv. pass the tongue over；词形变化：p:licked/i:licking/3:licks/d:licked/s:licks','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_600ed41f933082cf35',NULL,'lid','/lid/','n. 盖子, 限制, 眼睑\nvt. 给...盖盖子；英英释义：n. a movable top or cover (hinged or separate) for closing the opening at the top of a box, chest, jar, pan, etc.；词形变化：s:lids/p:lidded','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_774fdb11acff1d3bf8',NULL,'lifetime','/''laiftaim/','n. 一生, 终生\na. 一生的, 终生的；英英释义：n the period during which something is functional (as between birth and death)；词形变化：s:lifetimes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_9caf5b45a8bde20816',NULL,'lift','/lift/','n. 举起, 帮助, 昂扬, 电梯\nvt. 升高, 提高, 鼓舞, 清偿, 空运, 举起, 剽窃\nvi. 升起, 消散, 耸立；英英释义：n. the act of giving temporary assistance\nn. a wave that lifts the surface of the water or ground\nn. a device worn in a shoe or boot to make the wearer look taller or to correct a shortened leg\nn. one of the layers forming the heel of a shoe or boot；词形变化：p:lifted/d:lifted/i:lifting/s:lifts/3:lifts','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_fefbec0278dc4730c0',NULL,'lightning','/''laitniŋ/','n. 闪电\nvi. 闪电\na. 闪电的；英英释义：n. abrupt electric discharge from cloud to cloud or from cloud to earth accompanied by the emission of light\nn. the flash of light that accompanies an electric discharge in the atmosphere (or something resembling such a flash); can scintillate for a second or more；词形变化：s:lightnings','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
