INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f8257c989b19f5aa65',NULL,'likely','/''laikli/','a. 有可能的, 合适的, 前途有望的\nadv. 或许, 可能；英英释义：a. has a good chance of being the case or of coming about\ns. expected to become or be; in prospect\ns. within the realm of credibility；词形变化：t:likeliest','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_196de4856aed79488b',NULL,'likewise','/''laikwaiz/','adv. 同样地, 也；英英释义：r in like or similar manner\nr in addition\nr equally','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_94a5b4def07b60fb10',NULL,'limb','/lim/','n. 四肢, 枝干, 翼, 边缘\nvt. 切断...之手足；英英释义：n. one of the jointed appendages of an animal used for locomotion or grasping: arm; leg; wing; flipper\nn. any of the main branches arising from the trunk or a bough of a tree\nn. (astronomy) the circumferential edge of the apparent disc of the sun or the moon or a planet\nn. either of the two halves of a bow from handle to tip；词形变化：s:limbs/p:limbed','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4afb751c314f0b2630',NULL,'limit','/''limit/','n. 界限, 边界, 限度, 极限, 限制\nvt. 限制, 限定；英英释义：n. the greatest possible degree of something\nn. as far as something can go\nn. the boundary of a specific area\nn. the mathematical value toward which a function goes as the independent variable approaches infinity；词形变化：s:limits/d:limited/3:limits/i:limiting/p:limited','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f335f31d1391bcde3c',NULL,'limitation','/.limi''teiʃәn/','n. 限制, 缺陷, 限额\n[医] 限界, 限制, 限度；英英释义：n. the quality of being limited or restricted\nn. (law) a time period after which suits cannot be brought\nn. an act of limiting or restricting (as by regulation)；词形变化：s:limitations','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2df3447c557849a705',NULL,'limited','/''limitid/','a. 有限制的, 有限的, 有限责任的\nn. 特别快车；英英释义：a. small in range or scope\ns. including only a part\ns. mediocre\ns. not excessive；词形变化：0:limit/1:dp/d:limited/p:limited','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1eb7dfb4e40a8fd9a9',NULL,'limp','/limp/','n. 跛行\na. 柔软的, 无力的, 软弱的\nvi. 跛行；英英释义：v. walk impeded by some physical limitation or injury\nv. proceed slowly or with difficulty\ns. not firm\ns. lacking in strength or firmness or resilience；词形变化：p:limped/i:limping/d:limped/3:limps/s:limps/t:limpest','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_839d7e41658611c37c',NULL,'line','/lain/','n. 列, 线, 绳, 电线, 线路, 路线, 航线, 作业线, 界线, 战线, 外形, 排, 家系\nvt. 排成一行, 顺...排列, 划线于, 加衬里, 使有线条, 使起皱纹\nvi. 排队\n[计] 线路；英英释义：n. a formation of people or things one beside another\nn. a mark that is long relative to its width\nn. a formation of people or things one behind another\nn. a length (straight or curved) without breadth or thickness; the trace of a moving point；词形变化：s:lines/d:lined/i:lining/p:lined/3:lines','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
