INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b926bb8b8bbbba209e',NULL,'link','/liŋk/','n. 环, 连结物, 链接, 火把\nvt. 连结, 联合, 挽住\nvi. 连接起来\n[计] 连接, 链路；英英释义：n. the means of connection between things linked in series\nn. a fastener that serves to join or connect\nn. a unit of length equal to 1/100 of a chain\nn. (computing) an instruction that connects one part of a program or an element on a list to another program or list；词形变化：d:linked/s:links/i:linking/3:links/p:linked','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_005cf4dea5965de08c',NULL,'lion','/''laiәn/','n. 狮子, 狮子(星)座, 国际狮子会会员；英英释义：n. large gregarious predatory feline of Africa and India having a tawny coat with a shaggy mane in the male\nn. a celebrity who is lionized (much sought after)；词形变化：s:lions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_082ecdacebcdd25ca7',NULL,'lip','/lip/','n. 唇, 口缘, 唇状构造\nvt. 以嘴唇碰, 轻轻说出\na. 口头上的\n[计] 大型互连网信息包；英英释义：n. either of two fleshy folds of tissue that surround the mouth and play a role in speaking\nn. (botany) either of the two parts of a bilabiate corolla or calyx\nn. either the outer margin or the inner margin of the aperture of a gastropod''s shell；词形变化：s:lips/d:lipped','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
