INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_32e6ca5841658c2a36',NULL,'liquor','/''likә/','n. 酒, 液体, 汁, 溶液\nvt. 浸水\nvi. 喝酒；英英释义：n. an alcoholic beverage that is distilled rather than fermented\nn. a liquid substance that is a solution (or emulsion or suspension) used or obtained in an industrial process\nn. the liquid in which vegetables or meat have be cooked；词形变化：s:liquors','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_cf14d0e55988124c1d',NULL,'list','/list/','n. 目录, 名单, 明细表, 布条, 条纹, 列表, 序列, 数据清单\nvt. 列出, 列于表上, 记入名单内, 装布条\nvi. 列于表上\n[计] 列表, 序列, 数据清单；英英释义：n. a database containing an ordered array of items (names or topics)\nv. give or make a list of; name individually; give the names of\nv. include in a list\nv. cause to lean to the side；词形变化：s:lists/d:listed/p:listed/3:lists/i:listing','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
