INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_166abcc279948786e3',NULL,'lobby','/''lɒbi/','n. 大厅, 休息室, 游说议员者\nvi. 游说议员, 游说\nvt. 游说；英英释义：n. the people who support some common cause or business or principle or sectional interest\nn. a group of people who try actively to influence legislation\nv. detain in conversation by or as if by holding on to the outer garments of; as for political or economic favors；词形变化：s:lobbies/i:lobbying/d:lobbied/p:lobbied/3:lobbies','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
