INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_3f493256ca210ae84e',NULL,'locomotive','/.lәukә''mәutiv/','n. 火车头, 机车\na. 运转的, 火车头的, 移动的；英英释义：n. a wheeled vehicle consisting of a self-propelled engine that is used to draw trains along railway tracks\na. of or relating to locomotion；词形变化：s:locomotives','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ac21b1f67bfcd3fedd',NULL,'lodge','/lɒdʒ/','n. 小屋, 门房, 支部, 旅舍, 分会\nvi. 临时住宿, 倒伏, 寄宿, 投宿\nvt. 安顿, 容纳, 提出, 把...射入, 存放；英英释义：n. English physicist who studied electromagnetic radiation and was a pioneer of radiotelegraphy (1851-1940)\nn. small house at the entrance to the grounds of a country mansion; usually occupied by a gatekeeper or gardener\nn. a small (rustic) house used as a temporary shelter\nn. any of various Native American dwellings；词形变化：d:lodged/i:lodging/p:lodged/s:lodges/3:lodges','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_72c357f3fe4ac00608',NULL,'lofty','/''lɒfti/','a. 高的, 傲慢的, 崇高的, 高级的, 玄虚的；英英释义：s of high moral or intellectual value; elevated in nature or style\ns of imposing height; especially standing out above others\ns having or displaying great dignity or nobility；词形变化：r:loftier/t:loftiest','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a186ed8f6da968098f',NULL,'log','/lɒg/','n. 记录, 圆木, 日志, 计程仪\nvt. 伐木, 切, 航行\nvi. 伐木\n[计] 日志；英英释义：n. a segment of the trunk of a tree when stripped of branches\nn. a written record of messages sent or received\nn. a written record of events on a voyage (of a ship or plane)\nn. measuring instrument that consists of a float that trails from a ship by a knotted line in order to measure the ship''s speed through the water；词形变化：s:logs/d:logged/i:logging/p:logged/3:logs','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c3c22d58d7798ea116',NULL,'logic','/''lɒdʒik/','n. 逻辑, 逻辑学, 推理的方法, 推理, 逻辑性\n[计] 逻辑；英英释义：n. the branch of philosophy that analyzes inference\nn. reasoned and reasonable judgment\nn. the principles that guide reasoning within a given field or situation\nn. the system of operations performed by a computer that underlies the machine''s representation of logical operations；词形变化：s:logics','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_33ed7ba4ef03bb34c9',NULL,'logical','/''lɒdʒikәl/','a. 合乎逻辑的, 合理的\n[法] 逻辑的, 符合逻辑的；英英释义：a. capable of or reflecting the capability for correct and valid reasoning；词形变化：s:logicals','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
