INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_358cb608f7845bd74f',NULL,'longitude','/''lɒndʒitju:d/','n. 经度, 经线\n[电] 经度；英英释义：n. the angular distance between a point on any meridian and the prime meridian at Greenwich；词形变化：s:longitudes','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4ce40b1e281a3e3196',NULL,'loom','/lu:m/','n. 织布机, 若隐若现的景象\nvi. 朦胧地出现, 隐约可见, 可怕地出现；英英释义：n. a textile machine for weaving yarn into a textile\nv. come into view indistinctly, often threateningly\nv. appear very large or occupy a commanding position\nv. weave on a loom；词形变化：p:loomed/3:looms/i:looming/s:looms/d:loomed','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d8693a19ad8b153739',NULL,'loop','/lu:p/','n. 环, 圈, 弯曲部分, 循环\nvt. 使成环, 以圈结, 以环连结\nvi. 打环, 翻筋斗\n[计] 循环；英英释义：n. anything with a round or oval shape (formed by a curve that is closed and does not intersect itself)\nn. an inner circle of advisors (especially under President Reagan)\nn. the basic pattern of the human fingerprint\nn. a computer program that performs a series of instructions repeatedly until some specified condition is satisfied；词形变化：s:loops/i:looping/d:looped/p:looped/3:loops','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8d3cc62d405f3a11cd',NULL,'loose','/lu:s/','n. 发射, 放任, 放纵\na. 宽松的, 松的, 宽的, 不牢固的, 散漫的, 自由的, 不精确的\nvt. 释放, 放枪, 开船\nvi. 变松, 开火\nadv. 松散地；英英释义：a. not compact or dense in structure or arrangement\ns. (of a ball in sport) not in the possession or control of any player\na. not tight; not closely constrained or constricted or constricting\ns. not tense or taut；词形变化：p:loosed/i:loosing/d:loosed/3:looses','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_724faa8e52517b1fdb',NULL,'loosen','/lu:sn/','vt. 放松, 松开, 解除\nvi. 变松, 松弛；英英释义：v. make loose or looser\nv. make less dense\nv. become loose or looser or less tight；词形变化：p:loosened/d:loosened/i:loosening/3:loosens','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_33682d56b556099d11',NULL,'lord','/lɒ:d/','n. 统治者, 阁下, 上帝\nvi. 称王, 作威作福\nvt. 使成贵族；英英释义：n. a titled peer of the realm\nv. make a lord of someone；词形变化：i:lording/p:lorded/3:lords/d:lorded','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_fb211892c132b93e54',NULL,'lorry','/''lɒri/','n. 卡车, 货车\n[化] 载重汽车；英英释义：n. a large low horse-drawn wagon without sides\nn. a large truck designed to carry heavy loads; usually without sides；词形变化：s:lorries','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d86ece3b6905f49a13',NULL,'lose','/lu:z/','vt. 遗失, 损失, 丢失, 使失去, 错过, 浪费, 迷失, 使迷路, 输去, 使沉溺于\nvi. 受损失, 失败；英英释义：v. fail to keep or to maintain; cease to have, either physically or in an abstract sense\nv. fail to win\nv. suffer the loss of a person through death or removal\nv. miss from one''s possessions; lose sight of；词形变化：d:lost/p:lost/i:losing/3:loses','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c849712966c6905bac',NULL,'loss','/lɒs/','n. 损失, 遗失, 失败, 输, 错过, 伤亡\n[化] 损失; 损耗；英英释义：n. something that is lost\nn. gradual decline in amount or activity\nn. the act of losing someone or something\nn. the disadvantage that results from losing something；词形变化：s:losses','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
